const checkpoints = [];

const collections = JSON.parse(localStorage.getItem('collections') || '[]');
const collectionItems = JSON.parse(localStorage.getItem('collection_items') || '[]');
const species = JSON.parse(localStorage.getItem('species') || '[]');

// Build species map
const speciesMap = new Map();
for (const s of species) {
  if (s && s.id) speciesMap.set(s.id, s);
}

// Map collection_id -> array of species_ids
const itemsByCollection = new Map();
for (const ci of collectionItems) {
  if (!ci || !ci.collection_id || !ci.species_id) continue;
  if (!itemsByCollection.has(ci.collection_id)) itemsByCollection.set(ci.collection_id, []);
  itemsByCollection.get(ci.collection_id).push(ci.species_id);
}

let bestCount = 0;
for (const [colId, speciesIds] of itemsByCollection.entries()) {
  const uniqueIds = Array.from(new Set(speciesIds));
  let count = 0;
  for (const sid of uniqueIds) {
    const s = speciesMap.get(sid);
    if (!s) continue;
    if (s.habitat_type !== 'marine') continue;
    if (typeof s.min_depth_m !== 'number' || s.min_depth_m < 1000) continue;
    if (typeof s.min_length_cm !== 'number' || s.min_length_cm < 10) continue;
    count++;
  }
  if (count > bestCount) bestCount = count;
}

// Checkpoints reward how many qualifying species the best collection contains
checkpoints.push({ passed: bestCount >= 1, weight: 0.34 });
checkpoints.push({ passed: bestCount >= 2, weight: 0.33 });
checkpoints.push({ passed: bestCount >= 3, weight: 0.33 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const comparisonSets = JSON.parse(localStorage.getItem('comparison_sets') || '[]');
const comparisonItems = JSON.parse(localStorage.getItem('comparison_items') || '[]');
const species = JSON.parse(localStorage.getItem('species') || '[]');

// Map of conservation status severity
const severityMap = { cr: 7, en: 6, vu: 5, nt: 4, lc: 3, dd: 2, ne: 1 };

// All Tridacna species
const tridacnaSpecies = species.filter(s => s && typeof s.genus_id === 'string' && s.genus_id.toLowerCase() === 'tridacna');
if (!tridacnaSpecies || tridacnaSpecies.length === 0) {
  return 0;
}

// Find the most threatened Tridacna species (could be a tie)
let maxSeverity = -1;
let bestSpeciesIds = [];
for (const s of tridacnaSpecies) {
  const sev = severityMap[s.conservation_status] || 0;
  if (sev > maxSeverity) {
    maxSeverity = sev;
    bestSpeciesIds = [s.id];
  } else if (sev === maxSeverity) {
    bestSpeciesIds.push(s.id);
  }
}

let hasPerfectSet = false;
for (const set of comparisonSets) {
  if (!set || !set.id) continue;
  const items = comparisonItems.filter(ci => ci && ci.comparison_set_id === set.id);
  const uniqueSpeciesIds = Array.from(new Set(items.map(ci => ci.species_id).filter(Boolean)));
  // Must be a single-species comparison
  if (uniqueSpeciesIds.length !== 1) continue;
  const sid = uniqueSpeciesIds[0];
  if (bestSpeciesIds.includes(sid)) {
    hasPerfectSet = true;
    break;
  }
}

checkpoints.push({ passed: hasPerfectSet, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const collections = JSON.parse(localStorage.getItem('collections') || '[]');
const collectionItems = JSON.parse(localStorage.getItem('collection_items') || '[]');
const species = JSON.parse(localStorage.getItem('species') || '[]');
const distributions = JSON.parse(localStorage.getItem('species_distributions') || '[]');
const regions = JSON.parse(localStorage.getItem('regions') || '[]');

// Find North America region id
let northAmericaId = null;
for (const r of regions) {
  if (!r) continue;
  if (r.name === 'North America' || r.id === 'north_america' || r.code === 'NA') {
    northAmericaId = r.id;
    break;
  }
}
if (!northAmericaId) {
  return 0;
}

// Index species and distributions
const speciesMap = new Map();
for (const s of species) {
  if (s && s.id) speciesMap.set(s.id, s);
}

const distsBySpecies = new Map();
for (const d of distributions) {
  if (!d || !d.species_id) continue;
  if (!distsBySpecies.has(d.species_id)) distsBySpecies.set(d.species_id, []);
  distsBySpecies.get(d.species_id).push(d);
}

// Map collection -> qualifying invasive freshwater species in North America
const itemsByCollection = new Map();
for (const ci of collectionItems) {
  if (!ci || !ci.collection_id || !ci.species_id) continue;
  if (!itemsByCollection.has(ci.collection_id)) itemsByCollection.set(ci.collection_id, []);
  itemsByCollection.get(ci.collection_id).push(ci.species_id);
}

let bestCount = 0;
for (const [colId, speciesIds] of itemsByCollection.entries()) {
  const uniqueIds = Array.from(new Set(speciesIds));
  let count = 0;
  for (const sid of uniqueIds) {
    const s = speciesMap.get(sid);
    if (!s) continue;
    if (s.habitat_type !== 'freshwater') continue;
    const dists = distsBySpecies.get(s.id) || [];
    const hasQualifyingNA = dists.some(d => {
      if (!d.is_present) return false;
      if (d.region_id !== northAmericaId) return false;
      if (typeof d.first_record_year !== 'number' || d.first_record_year < 1950) return false;
      const status = d.occurrence_status;
      const invasiveFlag = d.is_invasive === true || d.is_introduced === true || status === 'invasive' || status === 'introduced';
      return invasiveFlag;
    });
    if (!hasQualifyingNA) continue;
    count++;
  }
  if (count > bestCount) bestCount = count;
}

checkpoints.push({ passed: bestCount >= 1, weight: 0.5 });
checkpoints.push({ passed: bestCount >= 2, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const collections = JSON.parse(localStorage.getItem('collections') || '[]');
const collectionItems = JSON.parse(localStorage.getItem('collection_items') || '[]');
const species = JSON.parse(localStorage.getItem('species') || '[]');
const distributions = JSON.parse(localStorage.getItem('species_distributions') || '[]');
const regions = JSON.parse(localStorage.getItem('regions') || '[]');

// Find Indo-Pacific region id
let indoPacificId = null;
for (const r of regions) {
  if (!r) continue;
  if (r.name === 'Indo-Pacific' || r.id === 'indo_pacific' || r.code === 'indo_pacific') {
    indoPacificId = r.id;
    break;
  }
}
if (!indoPacificId) {
  return 0;
}

// Index distributions by species
const distsBySpecies = new Map();
for (const d of distributions) {
  if (!d || !d.species_id) continue;
  if (!distsBySpecies.has(d.species_id)) distsBySpecies.set(d.species_id, []);
  distsBySpecies.get(d.species_id).push(d);
}

// Candidate cephalopods in Indo-Pacific with max_length_cm >= 50
const candidates = [];
for (const s of species) {
  if (!s || !s.id) continue;
  if (!s.class_id || s.class_id.toLowerCase() !== 'cephalopoda') continue;
  if (typeof s.max_length_cm !== 'number' || s.max_length_cm < 50) continue;
  const dists = distsBySpecies.get(s.id) || [];
  const inIndoPacific = dists.some(d => d.is_present && d.region_id === indoPacificId);
  if (!inIndoPacific) continue;
  candidates.push(s);
}

if (candidates.length === 0) {
  return 0;
}

let maxLen = -Infinity;
for (const s of candidates) {
  if (typeof s.max_length_cm === 'number' && s.max_length_cm > maxLen) {
    maxLen = s.max_length_cm;
  }
}

const largestIds = candidates.filter(s => s.max_length_cm === maxLen).map(s => s.id);

// Map collections -> species
const itemsByCollection = new Map();
for (const ci of collectionItems) {
  if (!ci || !ci.collection_id || !ci.species_id) continue;
  if (!itemsByCollection.has(ci.collection_id)) itemsByCollection.set(ci.collection_id, []);
  itemsByCollection.get(ci.collection_id).push(ci.species_id);
}

let hasPerfectCollection = false;
for (const [colId, speciesIds] of itemsByCollection.entries()) {
  const uniqueIds = Array.from(new Set(speciesIds.filter(Boolean)));
  if (uniqueIds.length !== 1) continue;
  const sid = uniqueIds[0];
  if (largestIds.includes(sid)) {
    hasPerfectCollection = true;
    break;
  }
}

checkpoints.push({ passed: hasPerfectCollection, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const favorites = JSON.parse(localStorage.getItem('favorite_resources') || '[]');
const resources = JSON.parse(localStorage.getItem('teaching_resources') || '[]');

const resourceMap = new Map();
for (const r of resources) {
  if (r && r.id) resourceMap.set(r.id, r);
}

const qualifyingFavorites = favorites.filter(f => {
  if (!f || !f.resource_id) return false;
  const r = resourceMap.get(f.resource_id);
  if (!r) return false;
  const keywords = Array.isArray(r.keywords) ? r.keywords.map(k => String(k).toLowerCase()) : [];
  const hasCamouflageKeyword = keywords.some(k => k.includes('cephalopod camouflage'));
  if (!hasCamouflageKeyword) return false;
  if (typeof r.target_age_min !== 'number' || typeof r.target_age_max !== 'number') return false;
  if (r.target_age_min < 12 || r.target_age_max > 14) return false;
  if (typeof r.publication_year !== 'number') return false;
  if (r.publication_year < 2019 || r.publication_year > 2024) return false;
  return true;
});

checkpoints.push({ passed: qualifyingFavorites.length >= 1, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const comparisonSets = JSON.parse(localStorage.getItem('comparison_sets') || '[]');
const comparisonItems = JSON.parse(localStorage.getItem('comparison_items') || '[]');
const distributions = JSON.parse(localStorage.getItem('species_distributions') || '[]');
const regions = JSON.parse(localStorage.getItem('regions') || '[]');

let japanId = null;
let australiaId = null;
for (const r of regions) {
  if (!r) continue;
  if (!japanId && (r.name === 'Japan' || r.id === 'japan' || r.code === 'JP')) japanId = r.id;
  if (!australiaId && (r.name === 'Australia' || r.id === 'australia' || r.code === 'AU')) australiaId = r.id;
}
if (!japanId || !australiaId) {
  return 0;
}

// Presence map: species_id -> { jp: bool, au: bool }
const presence = new Map();
for (const d of distributions) {
  if (!d || !d.species_id || !d.is_present) continue;
  if (d.region_id !== japanId && d.region_id !== australiaId) continue;
  const entry = presence.get(d.species_id) || { jp: false, au: false };
  if (d.region_id === japanId) entry.jp = true;
  if (d.region_id === australiaId) entry.au = true;
  presence.set(d.species_id, entry);
}

// Map comparison_set -> species_ids
const itemsBySet = new Map();
for (const ci of comparisonItems) {
  if (!ci || !ci.comparison_set_id || !ci.species_id) continue;
  if (!itemsBySet.has(ci.comparison_set_id)) itemsBySet.set(ci.comparison_set_id, []);
  itemsBySet.get(ci.comparison_set_id).push(ci.species_id);
}

let hasBothSpeciesSet = false;
let hasFullRequirementSet = false;

for (const set of comparisonSets) {
  if (!set || !set.id) continue;
  const speciesIds = Array.from(new Set((itemsBySet.get(set.id) || []).filter(Boolean)));
  if (speciesIds.length === 0) continue;

  const bothRegions = [];
  const japanOnly = [];

  for (const sid of speciesIds) {
    const p = presence.get(sid);
    if (!p) continue;
    if (p.jp && p.au) bothRegions.push(sid);
    if (p.jp && !p.au) japanOnly.push(sid);
  }

  if (bothRegions.length > 0) {
    hasBothSpeciesSet = true;
  }
  if (bothRegions.length > 0 && japanOnly.length > 0) {
    hasFullRequirementSet = true;
    // We don't break so we can still correctly set hasBothSpeciesSet, but it's already true
  }
}

checkpoints.push({ passed: hasBothSpeciesSet, weight: 0.4 });
checkpoints.push({ passed: hasFullRequirementSet, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const bookmarks = JSON.parse(localStorage.getItem('bookmarked_species') || '[]');
const species = JSON.parse(localStorage.getItem('species') || '[]');
const distributions = JSON.parse(localStorage.getItem('species_distributions') || '[]');
const regions = JSON.parse(localStorage.getItem('regions') || '[]');
const taxa = JSON.parse(localStorage.getItem('taxa') || '[]');

// Find Muricidae family id
let muricidaeId = null;
for (const t of taxa) {
  if (!t) continue;
  if (t.rank === 'family' && t.name === 'Muricidae') {
    muricidaeId = t.id;
    break;
  }
}
if (!muricidaeId) {
  muricidaeId = 'muricidae';
}

// Find Western Atlantic region id
let waId = null;
for (const r of regions) {
  if (!r) continue;
  if (r.name === 'Western Atlantic' || r.id === 'western_atlantic' || r.code === 'western_atlantic') {
    waId = r.id;
    break;
  }
}
if (!waId) {
  return 0;
}

// Index distributions by species
const distsBySpecies = new Map();
for (const d of distributions) {
  if (!d || !d.species_id) continue;
  if (!distsBySpecies.has(d.species_id)) distsBySpecies.set(d.species_id, []);
  distsBySpecies.get(d.species_id).push(d);
}

// Muricidae species present in Western Atlantic
const muricidaeWA = [];
for (const s of species) {
  if (!s || !s.id) continue;
  if (s.family_id !== muricidaeId) continue;
  const dists = distsBySpecies.get(s.id) || [];
  const presentInWA = dists.some(d => d.is_present && d.region_id === waId);
  if (!presentInWA) continue;
  muricidaeWA.push(s);
}

if (muricidaeWA.length === 0) {
  return 0;
}

// Find earliest year_described among Muricidae in Western Atlantic
let minYear = Infinity;
for (const s of muricidaeWA) {
  if (typeof s.year_described === 'number' && s.year_described < minYear) {
    minYear = s.year_described;
  }
}
if (!isFinite(minYear)) {
  return 0;
}

const earliestIds = muricidaeWA.filter(s => s.year_described === minYear).map(s => s.id);

const muricidaeWAIds = new Set(muricidaeWA.map(s => s.id));
const bookmarkedIds = new Set(bookmarks.map(b => b && b.species_id).filter(Boolean));

const bookmarkedMuricidaeWA = Array.from(bookmarkedIds).filter(id => muricidaeWAIds.has(id));
const bookmarkedEarliest = Array.from(bookmarkedIds).filter(id => earliestIds.includes(id));

// Partial credit: any Western Atlantic Muricidae bookmarked; full credit: earliest one bookmarked
checkpoints.push({ passed: bookmarkedMuricidaeWA.length >= 1, weight: 0.4 });
checkpoints.push({ passed: bookmarkedEarliest.length >= 1, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

