const collectionItems = JSON.parse(localStorage.getItem('collection_items') || '[]');
const species = JSON.parse(localStorage.getItem('species') || '[]');

const speciesMap = new Map();
for (const s of species) {
  if (s && s.id) speciesMap.set(s.id, s);
}

const itemsByCollection = new Map();
for (const ci of collectionItems) {
  if (!ci || !ci.collection_id || !ci.species_id) continue;
  if (!itemsByCollection.has(ci.collection_id)) itemsByCollection.set(ci.collection_id, []);
  itemsByCollection.get(ci.collection_id).push(ci.species_id);
}

let bestCount = 0;
for (const [colId, speciesIds] of itemsByCollection.entries()) {
  const uniqueIds = Array.from(new Set(speciesIds));
  let count = 0;
  for (const sid of uniqueIds) {
    const s = speciesMap.get(sid);
    if (!s) continue;
    if (!s.class_id || s.class_id.toLowerCase() !== 'gastropoda') continue;
    if (s.radula_type !== 'toxoglossan') continue;
    count++;
  }
  if (count > bestCount) bestCount = count;
}

checkpoints.push({ passed: bestCount >= 1, weight: 0.34 });
checkpoints.push({ passed: bestCount >= 2, weight: 0.33 });
checkpoints.push({ passed: bestCount >= 3, weight: 0.33 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
